				IRI buildKey = vf.createIRI(EX, "buildKey");
				IRI asymLargeKey = vf.createIRI(EX, "asymLargeKey");
				IRI asymSmallKey = vf.createIRI(EX, "asymSmallKey");
				IRI outerValue = vf.createIRI(EX, "outerValue");
				IRI blocked = vf.createIRI(EX, "blocked");
